New algorithm: For each order, evaluate all existing non-empty assigns plus one empty assign via cost increase calculation after simulated insertion, then pick the minimal-cost valid insertion; if none exists, create a new assign and insert there.}
func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	type cand struct {
		idx       int
		costDelta float64
		ok        bool
	}
	for jj := range oris {
		best := cand{-1, 0, false}
		limit := dispatch.AssignsLen
		if limit < MAXASSIGNS {
			limit++
		}
		for ii := 0; ii < limit; ii++ {
			assignIdx := ii
			if ii == dispatch.AssignsLen {
				dispatch.Assigns[ii].RemoveShip(-1)
			}
			prevCost := dispatch.Assigns[assignIdx].Cost
			addOk := dispatch.Assigns[assignIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			if addOk {
				dispatch.Assigns[assignIdx].GenRoute()
				newCost := dispatch.Assigns[assignIdx].Cost
				if newCost >= 0 {
					delta := newCost - prevCost
					if !best.ok || delta < best.costDelta {
						best.idx = assignIdx
						best.costDelta = delta
						best.ok = true
					}
				}
			}
			dispatch.Assigns[assignIdx].RemoveShip(total_ship + jj)
			dispatch.Assigns[assignIdx].GenRoute()
		}
		insertIdx := best.idx
		if insertIdx < 0 {
			for ii := 0; ii <= dispatch.AssignsLen; ii++ {
				if ii == dispatch.AssignsLen {
					if dispatch.AssignsLen < MAXASSIGNS {
						dispatch.Assigns[ii].RemoveShip(-1)
						insertIdx = ii
						break
					}
					continue
				}
				if dispatch.Assigns[ii].AddShip(total_ship+jj, oris[jj], dess[jj]) {
					dispatch.Assigns[ii].GenRoute()
					if dispatch.Assigns[ii].Cost >= 0 {
						insertIdx = ii
						break
					}
					dispatch.Assigns[ii].RemoveShip(total_ship + jj)
					dispatch.Assigns[ii].GenRoute()
				}
			}
		}
		if insertIdx >= 0 {
			dispatch.Assigns[insertIdx].RemoveShip(total_ship + jj)
			dispatch.Assigns[insertIdx].AddShip(total_ship+jj, oris[jj], dess[jj])
			dispatch.Assigns[insertIdx].GenRoute()
			if insertIdx >= dispatch.AssignsLen && dispatch.AssignsLen < MAXASSIGNS {
				dispatch.AssignsLen++
			}
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch

